18	    func connectForSelected(identifier: UUID,
19	                            done: @escaping ((CBPeripheral) -> Void),
20	                            failure: @escaping ((Error) -> Void)) {
21	        if isScaning {
22	           stopScanning()
23	        }
24	        if let result = scanResultItems.first(where: { $0.peripheral.identifier == identifier }) {
25	            self.currentPeripheral = result.peripheral
26	
27	            if result.peripheral.state == .connecting {
28	                BBLog.info(tag: MirrorBleDefine.logTag, "蓝牙 UUID：\(result.peripheral.identifier) 正在连接中，发起断连")
29	                
30	                MirrorBleHelper.shared.disconnect(peripheral: result.peripheral)
31	                
32	                // 延迟0.1秒后执行
33	                DispatchQueue.main.asyncAfter(deadline: .now() + 0.1) {
34	                    self.connectGetDoneCharacteristics(peripheral: result.peripheral, done: {
35	                        done(result.peripheral)
36	                    }, failure: failure)
37	                }
38	            } else {
39	                connectGetDoneCharacteristics(peripheral: result.peripheral, done: {
40	                    done(result.peripheral)
41	                }, failure: failure)
42	            }
43	        }
44	    }
