46	    func connectGetDoneCharacteristics(peripheral: CBPeripheral,
47	                                       done: @escaping (() -> Void),
48	                                       failure: @escaping ((Error) -> Void)) {
49	        cancelConnecting()
50	        writeAbleCharacteristics = nil
51	        subscribedNotifyCharacteristics.removeAll()
52	        
53	        func authConnectedBle() {
54	            let targetUUID = CBUUID(string: MirrorBleDefine.serviceUUID)
55	            let characteristicRead = CBUUID(string: MirrorBleDefine.characterReadUUID)
56	            let characteristicWrite = CBUUID(string: MirrorBleDefine.characterWriteUUID)
57	            
58	            discoveredService(peripheral: peripheral, uuid: targetUUID)
59	            didDiscoverServicesSubject.sink { _ in
60	                
61	            } receiveValue: { (uuids, err) in
62	                if let err = err {
63	                    BBLog.info(tag: MirrorBleDefine.logTag, "发现服务失败:\(err)")
64	                    failure(err)
65	                } else {
66	                    BBLog.info(tag: MirrorBleDefine.logTag, "发现服务成功: \(uuids.map { $0.uuidString }.joined(separator: ","))")
67	                    if uuids.contains(targetUUID) {
68	                        BBLog.info(tag: MirrorBleDefine.logTag, "服务命中")
69	                        self.discoverCharacteristic(peripheral: peripheral,
70	                                                    targetUUID: targetUUID,
71	                                                    characteristicUUIDs: [characteristicRead, characteristicWrite])
72	                        
73	                        self.didDiscoveCharacteristicsSubject
74	                            .sink { _ in } receiveValue: { _, charas, error in
75	                                if let err = err {
76	                                    BBLog.info(tag: MirrorBleDefine.logTag, "发现特征失败:\(err))")
77	                                    failure(err)
78	                                } else {
79	                                    BBLog.info(tag: MirrorBleDefine.logTag, "发现特征成功")
80	                                    charas.forEach { chara in
81	                                        if chara.uuid == characteristicWrite {
82	                                            self.writeAbleCharacteristics = chara
83	                                        }
84	                                        if chara.uuid == characteristicRead {
85	                                            self.readAbleCharacteristics = chara
86	                                            self.subscribeToNotify(peripheral: peripheral, characteristic: chara)
87	                                            self.discoverDescriptor(peripheral: peripheral, characteristic: chara)
88	                                        }
89	                                    }
90	                                    
91	                                    self.didDiscoveDescriptorSubject
92	                                        .sink { _ in } receiveValue: { _, charas, error in
93	                                            if let err = err {
94	                                                BBLog.info(tag: MirrorBleDefine.logTag, "发现描述失败:\(err))")
95	                                                failure(err)
96	                                            } else {
97	                                                if let descriptor = self.readAbleCharacteristics?.descriptors?.first(where: { $0.uuid == CBUUID(string: MirrorBleDefine.descriptorReadUUID) }) {
98	                                                    
99	                                                    BBLog.info(tag: MirrorBleDefine.logTag, "写入描述")
100	
101	                                                    peripheral.writeValue(Data(MirrorBleDefine.ENABLE_NOTIFICATION_VALUE), for: descriptor)
102	                                                    
103	                                                    self.didDiscoveDescriptorNotify
104	                                                        .sink { _ in } receiveValue: { isNotify in
105	                                                            if isNotify {
106	                                                                BBLog.info(tag: MirrorBleDefine.logTag, "done～")
107	
108	                                                                done()
109	                                                            } else {
110	                                                                failure(MirrorBleHelperError.connectFail(err: nil))
111	                                                            }
112	                                                        }
113	                                                        .store(in: &self.conneceResultCancellables)
114	
115	                                                }
116	                                            }
117	                                        }
118	                                        .store(in: &self.conneceResultCancellables)
119	                                    
120	                                }
121	                        }.store(in: &self.conneceResultCancellables)
122	                    }
123	                }
124	            }.store(in: &self.conneceResultCancellables)
125	        }
126	        
127	        if peripheral.state == .connected {
128	            BBLog.info(tag: MirrorBleDefine.logTag, "蓝牙已经连接上，直接发现服务")
129	            authConnectedBle()
130	        } else {
131	            hitConnectedBle = false
132	
133	            connect(peripheral: peripheral)
134	            
135	            // 2 兜底
136	            DispatchQueue.main.asyncAfter(deadline: .now() + 2) {
137	                if !self.hitConnectedBle && self.findConnectedBR().first(where: { $0.identifier == peripheral.identifier }) != nil {
138	                    BBLog.info(tag: MirrorBleDefine.logTag, "BR经典蓝牙已配对，尝试修复冲突！")
139	                    self.disconnect(peripheral: peripheral)
140	                    DispatchQueue.main.asyncAfter(deadline: .now() + 1) {
141	                        self.connect(peripheral: peripheral)
142	                    }
143	                }
144	            }
145	            
146	            didConnectedSubject.sink { _ in
147	            } receiveValue: { [weak self] (peripheral, err) in
148	                guard let self = self else { return }
149	                if err == nil {
150	                    self.hitConnectedBle = true
151	                    // 1 正常
152	                    BBLog.info(tag: MirrorBleDefine.logTag, "正常连接流程！")
153	                    authConnectedBle()
154	                } else {
155	                    self.hitConnectedBle = true
156	                    BBLog.info(tag: MirrorBleDefine.logTag, "连接失败，Connect Fail: \(err?.localizedDescription ?? "")")
157	                    failure(err!)
158	                }
159	            }.store(in: &conneceResultCancellables)
160	        }
161	    }
